import{c as t,Z as i,Q as d,j as n,g as a,n as o,o as l,m as s}from"./chunks/framework.qjzPVSkb.js";const E=JSON.parse('{"title":"Embedding","description":"将文本、图像等数据转化为向量（数字数组）的技术——语义相近的内容向量距离更近","frontmatter":{"title":"Embedding","description":"将文本、图像等数据转化为向量（数字数组）的技术——语义相近的内容向量距离更近","difficulty":"intermediate"},"headers":[],"relativePath":"terms/embedding.md","filePath":"terms/embedding.md"}'),m={name:"terms/embedding.md"};function g(h,e,b,c,f,p){const r=i("DifficultyBadge");return d(),n("div",null,[e[0]||(e[0]=a("h1",{id:"embedding",tabindex:"-1"},[o("Embedding "),a("a",{class:"header-anchor",href:"#embedding","aria-label":'Permalink to "Embedding"'},"​")],-1)),l(r,{level:"intermediate"}),e[1]||(e[1]=s('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>Embedding（嵌入）是将文本、图像、音频等非结构化数据<strong>映射为固定长度的数值向量</strong>的技术。核心特性是：<strong>语义相近的内容，其向量在高维空间中的距离也相近</strong>。它是 RAG、语义搜索、推荐系统等技术的基础。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>想象你有 1000 本书，你想按主题把它们摆到书架上。一种方式是手工一本本分类。更好的方式是为每本书生成一个&quot;坐标&quot;（比如 [0.3, 0.8, -0.1, …]），让内容相似的书自动靠在一起——科幻挨着科幻，历史挨着历史。Embedding 做的事就是把任意的文本/图片变成一个 300 到 4096 维空间里的点，语义越接近，两个点之间的距离就越小。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>Embedding 模型通常基于 Transformer 架构训练，核心训练目标是让语义相近的文本产生相近的向量。常见的训练范式包括：</p><ul><li><strong>对比学习（Contrastive Learning）</strong>：拉近正样本对（如查询和对应文档）的距离，推远负样本对</li><li><strong>掩码语言建模（MLM）</strong>：BERT 风格的训练，从上下文预测被遮盖的词</li></ul><p>常用的 Embedding 模型：OpenAI <code>text-embedding-3</code> 系列、BGE（BAAI）、Cohere Embed、Sentence-BERT。维度越高通常表达能力越强，但存储和计算成本也越大。</p><p>两个向量之间的相似度常用<strong>余弦相似度（Cosine Similarity）</strong> 衡量：值越接近 1，两个向量的方向越一致，语义越相近。</p><p>Embedding 的典型应用场景包括：语义搜索、文本聚类、文本分类、异常检测、推荐系统。它也是 <a href="/ai-knowledge/terms/rag.html">RAG</a> 和 <a href="/ai-knowledge/terms/vector-db.html">向量数据库</a> 的底层基础。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/vector-db.html">向量数据库</a> —— 专门存储和检索 Embedding 向量的数据库</li><li><a href="/ai-knowledge/terms/rag.html">RAG</a> —— Embedding 是实现 RAG 检索环节的关键</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— LLM 内部也使用 Embedding 表示词和位置</li><li><a href="/ai-knowledge/terms/transformer.html">Transformer</a> —— 主流的 Embedding 模型基于 Transformer 架构</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>OpenAI Embeddings 文档：<a href="https://platform.openai.com/docs/guides/embeddings" target="_blank" rel="noreferrer">Embeddings Guide</a></li><li>MTEB Leaderboard：<a href="https://huggingface.co/spaces/mteb/leaderboard" target="_blank" rel="noreferrer">Massive Text Embedding Benchmark</a> —— 查看当前最好的 Embedding 模型</li><li>动手实验：用 BGE 模型对一段中文文本生成 Embedding，然后用余弦相似度比较不同句子的语义距离。</li></ul>',14))])}const _=t(m,[["render",g]]);export{E as __pageData,_ as default};
